#!/bin/bash
set -e

mkdir -p "$(dirname 'src/components/wedding/sections.tsx')"
echo '' | base64 -d > 'src/components/wedding/sections.tsx'
mkdir -p "$(dirname 'src/features/weddings/public-dto.ts')"
echo '' | base64 -d > 'src/features/weddings/public-dto.ts'
mkdir -p "$(dirname 'src/app/w/[slug]/page.tsx')"
